#include <iostream>#include <vector>#include <string> using namespace std; void solve() {    int n;    cin >> n;    string s;    cin >> s;     long long ans = 0;    vector<bool> seen(26, false);     for (int i = 0; i < n; i++) {        int char_val = s[i] - 'a';        if (!seen[char_val]) {            ans += (n - i);            seen[char_val] = true;        }    }    cout << ans << "\n";} int main() {    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin >> t;    while (t--) {        solve();    }    return 0;}